import pytest
from config import MAX_ATTEMPTS

def test_excessive_failed_logins_returns_429_and_notifies_patient(
    reset_rate_limit, invalid_sso_assertion, api_client,
    notification_stub, test_patient_id
):
    for i in range(1, MAX_ATTEMPTS + 1):
        r = api_client.post(
            "/portal/login",
            json={"sso_assertion": invalid_sso_assertion}
        )
        assert r.status_code == 401, f"attempt {i} should be 401"

    r_over = api_client.post(
        "/portal/login",
        json={"sso_assertion": invalid_sso_assertion}
    )
    assert r_over.status_code == 429, "attempt over limit must return 429"

    alerts = notification_stub.get_alerts(patient_id=test_patient_id)
    assert len(alerts) == 1, "exactly one rate-limit notification expected"
    assert alerts[0]["reason"] == "rate_limit_exceeded"

import pytest
from config import MAX_ATTEMPTS

def test_last_allowed_attempt_succeeds_and_next_is_rate_limited(
    reset_rate_limit, invalid_sso_assertion,
    valid_sso_assertion, api_client
):
    for i in range(1, MAX_ATTEMPTS + 1):
        r = api_client.post(
            "/portal/login",
            json={"sso_assertion": invalid_sso_assertion}
        )
        assert r.status_code == 401, f"attempt {i} should be 401"

    r_boundary = api_client.post(
        "/portal/login",
        json={"sso_assertion": valid_sso_assertion}
    )
    assert r_boundary.status_code == 429, \
        "valid creds after MAX_ATTEMPTS failures must still be blocked"
    assert "session_token" not in r_boundary.json(), \
        "no session must be issued when rate-limited"
